import{_ as i,o as e,c as a,ai as n}from"./chunks/framework.ampVZV4B.js";const k=JSON.parse('{"title":"MySQL 索引面试通关指南","description":"","frontmatter":{},"headers":[],"relativePath":"database/mysql-index.md","filePath":"database/mysql-index.md"}'),l={name:"database/mysql-index.md"};function t(d,s,r,o,h,p){return e(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="mysql-索引面试通关指南" tabindex="-1">MySQL 索引面试通关指南 <a class="header-anchor" href="#mysql-索引面试通关指南" aria-label="Permalink to “MySQL 索引面试通关指南”">​</a></h1><p>本文完全按照真实面试场景编排，按从高频到低频的顺序，带你手撕 MySQL 索引相关的各个核心考点。</p><hr><h3 id="❓-面试官-mysql-为什么默认使用-b-树作为索引结构-而不是红黑树或-b-树" tabindex="-1">❓ 面试官：MySQL 为什么默认使用 B+ 树作为索引结构？而不是红黑树或 B 树？ <a class="header-anchor" href="#❓-面试官-mysql-为什么默认使用-b-树作为索引结构-而不是红黑树或-b-树" aria-label="Permalink to “❓ 面试官：MySQL 为什么默认使用 B+ 树作为索引结构？而不是红黑树或 B 树？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 因为 B+ 树的层级更低，磁盘 IO 次数更少，而且叶子节点形成了双向链表，非常适合关系型数据库中最常见的范围查询。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>相比红黑树/二叉树</strong>：二叉树每个节点只有两个分支，数据量大时树会非常高。数据库索引存储在磁盘上，树的每一层通常对应一次磁盘 IO，导致磁盘 IO 次数过多。B+ 树是多路平衡查找树，通常 3-4 层就能支撑千万级数据。</li><li><strong>相比 B 树</strong>： <ul><li>B 树的所有节点都存完整的数据（记录或行指针），导致一页（默认16KB）能存的索引键很少，树变高，IO 变多。</li><li>B 树不支持范围查询，而 B+ 树只有叶子节点存数据，非叶子节点只存主键和指针，一页能装下极多的键。最关键的是，B+ 树的叶子节点有双向链表，<code>SELECT * WHERE id &gt; 10</code> 时只需要找到 10，然后顺着链表向后遍历即可。</li></ul></li></ol><p><strong>🌟 面试加分项（实战经验）：</strong> 在实际业务中，由于 B+ 树一页是 16KB，我们在设计表时，我会尽量让主键不要太大（比如尽量用自增 BIGINT/雪花算法，而不是无序的长字符串 UUID）。因为主键越短，一个数据页里能装下的索引键就越多，树的高度就会更低，查询速度就越快。同时，因为 InnoDB 二级索引（非聚簇索引）的叶子节点存的是主键值，主键短也能节省大量二级索引的存储空间。</p><hr><h3 id="❓-面试官-能说说你对聚簇索引和非聚簇索引的理解吗-什么是回表" tabindex="-1">❓ 面试官：能说说你对聚簇索引和非聚簇索引的理解吗？什么是回表？ <a class="header-anchor" href="#❓-面试官-能说说你对聚簇索引和非聚簇索引的理解吗-什么是回表" aria-label="Permalink to “❓ 面试官：能说说你对聚簇索引和非聚簇索引的理解吗？什么是回表？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 聚簇索引的数据和索引是保存在一起的（叶子节点就是完整的数据行），而非聚簇索引（二级索引）的叶子节点只保存了主键值。通过非聚簇索引查到主键后，再回到聚簇索引中去查完整数据的过程，就叫<strong>回表</strong>。</p><p><strong>📝 详细原理解析：</strong></p><ul><li><strong>聚簇索引（Clustered Index）</strong>：InnoDB 引擎的表必须有且只有一个聚簇索引，默认是主键。如果没有主键，会选择第一个非空的唯一索引；如果都没有，InnoDB 会自动生成一个隐式的 6 字节 ROW_ID 作为聚簇索引。</li><li><strong>非聚簇索引（Secondary Index）</strong>：我们平时针对 <code>username</code>、<code>phone</code> 等字段建的索引就是非聚簇索引。</li></ul><p><strong>回表过程举例</strong>：</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> email </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;test@example.com&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol><li>引擎先在 <code>idx_email</code> 这一棵 B+ 树上找到 <code>test@example.com</code> 对应的主键 ID（比如 id = 5）。</li><li>引擎拿着 <code>id = 5</code>，再去主键的 B+ 树（聚簇索引）中查找，获取这一行的完整数据。这个过程就是回表。</li></ol><p><strong>🌟 面试加分项（实战经验）：</strong> 因为回表需要多查一棵树，所以性能会有损耗。在开发中，对于高频的查询，我通常会尽量使用<strong>覆盖索引</strong>来避免回表。</p><hr><h3 id="❓-面试官-刚才提到了覆盖索引-能详细解释下吗" tabindex="-1">❓ 面试官：刚才提到了覆盖索引，能详细解释下吗？ <a class="header-anchor" href="#❓-面试官-刚才提到了覆盖索引-能详细解释下吗" aria-label="Permalink to “❓ 面试官：刚才提到了覆盖索引，能详细解释下吗？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 覆盖索引并不是一种具体的索引类型，而是一种<strong>查询优化手段</strong>。当我们要查询的列，都已经被包含在当前使用的索引中时，就不需要回表了，这就叫覆盖索引。</p><p><strong>📝 详细原理解析：</strong> 假设我们有联合索引 <code>idx_username_email (username, email)</code>。</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 触发覆盖索引，无需回表</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id, username, email </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> username </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;张三&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>因为联合索引的叶子节点里，本身就存了 <code>username</code>、<code>email</code> 以及主键 <code>id</code>。我们要查的这三个字段全都在索引树里，直接返回即可（执行计划 Extra 会显示 <code>Using index</code>）。</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- 需要回表</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> id, username, email, phone </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> username </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;张三&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>因为 <code>phone</code> 字段不在索引中，只能拿着 ID 回表去聚簇索引里拿 <code>phone</code>。</p><p><strong>🌟 面试加分项（实战经验）：</strong> 这也是为什么我们规约里严禁使用 <code>SELECT *</code> 的核心原因之一。<code>SELECT *</code> 几乎一定会导致回表。在实现某些分页列表或下拉框接口时，如果只返回 ID 和 Name，我一定会针对这两个字段建联合索引，利用覆盖索引把接口响应时间压到极低。</p><hr><h3 id="❓-面试官-什么是最左前缀匹配原则" tabindex="-1">❓ 面试官：什么是最左前缀匹配原则？ <a class="header-anchor" href="#❓-面试官-什么是最左前缀匹配原则" aria-label="Permalink to “❓ 面试官：什么是最左前缀匹配原则？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 在使用联合索引时，MySQL 会按照联合索引创建的顺序，从左到右依次匹配，如果遇到范围查询（<code>&gt;、&lt;、between、like</code>）就会停止匹配后面的列。</p><p><strong>📝 详细原理解析：</strong> 假设创建了联合索引 <code>(a, b, c)</code>，其实相当于创建了 <code>(a)</code>、<code>(a, b)</code>、<code>(a, b, c)</code> 三个索引。</p><ul><li><code>where a = 1 and b = 2 and c = 3</code>：完全走索引。</li><li><code>where a = 1 and c = 3</code>：只有 <code>a</code> 走索引，<code>c</code> 无法走索引（因为跳过了 <code>b</code>）。</li><li><code>where a &gt; 1 and b = 2</code>：<code>a</code> 走索引范围扫描，<code>b</code> 无法走索引（因为 <code>a</code> 是范围查询）。</li><li><code>where b = 2 and c = 3</code>：完全不走索引（没有最左侧的 <code>a</code>）。</li></ul><p><strong>🌟 面试加分项（实战经验）：</strong></p><ul><li><strong>顺序无关性</strong>：<code>where b = 2 and a = 1</code> 这种乱序的 SQL，MySQL 优化器会自动将其优化为 <code>a = 1 and b = 2</code>，所以能正常走索引。</li><li><strong>建索引的诀窍</strong>：在设计联合索引时，我会把<strong>区分度最高（基数最大）的字段放在最左边</strong>。另外，如果已经有了 <code>(a, b)</code> 索引，且业务频繁需要查 <code>a</code>，就不需要再单独建单列索引 <code>(a)</code> 了，避免冗余。</li></ul><hr><h3 id="❓-面试官-什么是索引下推-icp" tabindex="-1">❓ 面试官：什么是索引下推（ICP）？ <a class="header-anchor" href="#❓-面试官-什么是索引下推-icp" aria-label="Permalink to “❓ 面试官：什么是索引下推（ICP）？”">​</a></h3><p><em>频率：🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 索引下推（Index Condition Pushdown）是 MySQL 5.6 引入的优化机制。它把原本应该在 Server 层进行的回表过滤操作，&quot;下推&quot;到了引擎层（InnoDB）在遍历索引时提前过滤，从而减少回表的次数。</p><p><strong>📝 详细原理解析：</strong> 假设有联合索引 <code>(name, age)</code>，执行 SQL：</p><div class="language-sql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> users </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">WHERE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> name</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> LIKE</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;张%&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> AND</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> age </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 25</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>根据最左前缀原则，<code>name</code> 是范围查询，<code>age</code> 本来是无法走索引的。</p><ul><li><strong>没有 ICP（5.6 之前）</strong>：存储引擎根据 <code>张%</code> 找到 100 条符合的主键 ID，然后<strong>回表 100 次</strong>把完整记录取出来，返回给 Server 层，Server 层再去判断 <code>age = 25</code>。</li><li><strong>有 ICP（5.6 之后）</strong>：存储引擎在索引树上扫描时，发现虽然 <code>age</code> 没法用来精确定位，但索引树里明明有 <code>age</code> 的值！于是它在索引树里直接判断 <code>age</code> 是否等于 25。假设 100 个人里只有 2 个25岁，那就只需要<strong>回表 2 次</strong>。</li></ul><p>（执行计划 Extra 中看到 <code>Using index condition</code> 就代表触发了索引下推）。</p><hr><h3 id="❓-面试官-你能说出几个常见的索引失效场景吗" tabindex="-1">❓ 面试官：你能说出几个常见的索引失效场景吗？ <a class="header-anchor" href="#❓-面试官-你能说出几个常见的索引失效场景吗" aria-label="Permalink to “❓ 面试官：你能说出几个常见的索引失效场景吗？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 最常见的索引失效场景包括：对索引列使用函数或计算、发生隐式类型转换、LIKE 左模糊查询、不等于（<code>!=</code>、<code>&lt;&gt;</code>）以及 OR 条件中有未建索引的列。</p><p><strong>📝 详细原理解析：</strong></p><ol><li><strong>使用了函数/计算</strong>： <ul><li>失效：<code>WHERE DATE(create_time) = &#39;2024-01-01&#39;</code>（因为 B+ 树存的是原始值，用了函数就对应不上了）</li><li>优化：<code>WHERE create_time &gt;= &#39;2024-01-01&#39; AND create_time &lt; &#39;2024-01-02&#39;</code></li></ul></li><li><strong>隐式类型转换</strong>： <ul><li>失效：<code>WHERE phone = 13800138000</code>（表里 phone 是 varchar，传了 int，MySQL 会默认对列加 <code>CAST</code> 函数转换为整型，导致失效）</li></ul></li><li><strong>左模糊查询</strong>： <ul><li>失效：<code>WHERE name LIKE &#39;%张三&#39;</code>（B+ 树是按从左到右排序的，最左边是通配符就无法走树查找）</li></ul></li><li><strong>OR 条件错用</strong>： <ul><li><code>WHERE id = 1 OR remark = &#39;test&#39;</code>（如果 remark 没有索引，即使 id 有索引，也会全表扫描）</li></ul></li></ol><p><strong>🌟 面试加分项（实战经验）：</strong> 面试官其实很喜欢问隐式类型转换。在实际开发中，如果联表查询 <code>JOIN</code> 性能极差，我首先会检查关联的两个字段<strong>类型、长度、字符集排序规则（Collation）</strong>是否完全一致。如果有任何一个不一致，就会触发隐式转换，导致被驱动表索引失效，这是线上非常容易踩坑的地方。</p>`,53)])])}const g=i(l,[["render",t]]);export{k as __pageData,g as default};
